class Solution {
    public int binaryGap(int n) {
        int maxGap = 0, prev = -1;
        for (int i = 0; n > 0; i++) {
            if ((n & 1) == 1) {
                if (prev != -1) {
                    maxGap = Math.max(maxGap, i - prev);
                }
                prev = i;
            }
            n >>= 1;
        }
        return maxGap;
    }
}
